import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Line, Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const PollutionCharts = () => {
  const [chartData, setChartData] = useState(null);
  const [selectedType, setSelectedType] = useState('AIR_QUALITY');
  const [selectedLocation, setSelectedLocation] = useState('');
  const [locations, setLocations] = useState([]);
  const [loading, setLoading] = useState(false);

  const pollutionTypes = [
    { value: 'AIR_QUALITY', label: 'Air Quality (AQI)' },
    { value: 'WATER_QUALITY', label: 'Water Quality' },
    { value: 'NOISE_LEVEL', label: 'Noise Level (dB)' },
    { value: 'SOIL_POLLUTION', label: 'Soil Pollution' }
  ];

  useEffect(() => {
    fetchLocations();
  }, []);

  useEffect(() => {
    if (selectedLocation) {
      fetchChartData();
    }
  }, [selectedType, selectedLocation]);

  const fetchLocations = async () => {
    try {
      const response = await axios.get('http://localhost:8080/api/predictions/type/AIR_QUALITY');
      const uniqueLocations = [...new Set(response.data.map(p => p.location))];
      setLocations(uniqueLocations);
      if (uniqueLocations.length > 0) {
        setSelectedLocation(uniqueLocations[0]);
      }
    } catch (error) {
      console.error('Error fetching locations:', error);
    }
  };

  const fetchChartData = async () => {
    try {
      setLoading(true);
      const response = await axios.get(
        `http://localhost:8080/api/predictions/recent/${selectedLocation}/${selectedType}`
      );
      const predictions = response.data || [];
      
      if (predictions.length > 0) {
        const labels = predictions.map((_, i) => `T${i}`);
        const values = predictions.map(p => p.value);
        const colors = predictions.map(p => {
          const colorMap = {
            'GOOD': '#4caf50',
            'MODERATE': '#ff9800',
            'POOR': '#ff5722',
            'SEVERE': '#d32f2f',
            'CRITICAL': '#8b0000'
          };
          return colorMap[p.pollutionLevel] || '#999';
        });

        setChartData({
          labels,
          datasets: [
            {
              label: selectedType.replace(/_/g, ' '),
              data: values,
              borderColor: '#1976d2',
              backgroundColor: 'rgba(25, 118, 210, 0.1)',
              fill: true,
              tension: 0.4,
              pointBackgroundColor: colors,
              pointRadius: 6,
              pointHoverRadius: 8,
            }
          ]
        });
      }
    } catch (error) {
      console.error('Error fetching chart data:', error);
    } finally {
      setLoading(false);
    }
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: `${selectedType.replace(/_/g, ' ')} Trends for ${selectedLocation}`,
        font: { size: 16 }
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        title: {
          display: true,
          text: selectedType === 'NOISE_LEVEL' ? 'Decibels (dB)' : 'Index Value'
        }
      }
    }
  };

  return (
    <div style={{ padding: '20px', backgroundColor: '#f5f5f5', minHeight: '100vh' }}>
      <h1>Pollution Trends Analysis</h1>
      
      <div style={{ 
        display: 'flex', 
        gap: '20px', 
        marginBottom: '30px',
        flexWrap: 'wrap'
      }}>
        <div style={{ flex: 1, minWidth: '250px' }}>
          <label htmlFor="location-select">
            <strong>Select Location:</strong>
          </label>
          <select 
            id="location-select"
            value={selectedLocation} 
            onChange={(e) => setSelectedLocation(e.target.value)}
            style={{
              width: '100%',
              padding: '10px',
              marginTop: '5px',
              borderRadius: '4px',
              border: '1px solid #ddd',
              fontSize: '1rem'
            }}
          >
            {locations.map(loc => (
              <option key={loc} value={loc}>{loc}</option>
            ))}
          </select>
        </div>

        <div style={{ flex: 1, minWidth: '250px' }}>
          <label htmlFor="type-select">
            <strong>Pollution Type:</strong>
          </label>
          <select 
            id="type-select"
            value={selectedType} 
            onChange={(e) => setSelectedType(e.target.value)}
            style={{
              width: '100%',
              padding: '10px',
              marginTop: '5px',
              borderRadius: '4px',
              border: '1px solid #ddd',
              fontSize: '1rem'
            }}
          >
            {pollutionTypes.map(type => (
              <option key={type.value} value={type.value}>{type.label}</option>
            ))}
          </select>
        </div>
      </div>

      <div style={{
        backgroundColor: '#fff',
        padding: '20px',
        borderRadius: '8px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        marginBottom: '30px'
      }}>
        {loading ? (
          <div style={{ textAlign: 'center', padding: '40px', color: '#666' }}>
            Loading chart data...
          </div>
        ) : chartData ? (
          <div style={{ height: '400px', position: 'relative' }}>
            <Line data={chartData} options={chartOptions} />
          </div>
        ) : (
          <div style={{ textAlign: 'center', padding: '40px', color: '#999' }}>
            No data available for selected location and type
          </div>
        )}
      </div>

      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
        gap: '20px',
        marginBottom: '30px'
      }}>
        <div style={{
          backgroundColor: '#fff',
          padding: '20px',
          borderRadius: '8px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          borderLeft: '4px solid #4caf50'
        }}>
          <h3 style={{ marginTop: 0 }}>Good</h3>
          <p style={{ fontSize: '0.9rem', color: '#666' }}>Air Quality Index: 0-50</p>
        </div>
        <div style={{
          backgroundColor: '#fff',
          padding: '20px',
          borderRadius: '8px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          borderLeft: '4px solid #ff9800'
        }}>
          <h3 style={{ marginTop: 0 }}>Moderate</h3>
          <p style={{ fontSize: '0.9rem', color: '#666' }}>Air Quality Index: 51-100</p>
        </div>
        <div style={{
          backgroundColor: '#fff',
          padding: '20px',
          borderRadius: '8px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          borderLeft: '4px solid #ff5722'
        }}>
          <h3 style={{ marginTop: 0 }}>Poor</h3>
          <p style={{ fontSize: '0.9rem', color: '#666' }}>Air Quality Index: 101-200</p>
        </div>
        <div style={{
          backgroundColor: '#fff',
          padding: '20px',
          borderRadius: '8px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          borderLeft: '4px solid #d32f2f'
        }}>
          <h3 style={{ marginTop: 0 }}>Severe</h3>
          <p style={{ fontSize: '0.9rem', color: '#666' }}>Air Quality Index: 200+</p>
        </div>
      </div>
    </div>
  );
};

export default PollutionCharts;
